        }

        public override async Task Validation(Shift item, Result<Shift> executionResult)
        {
            if (await UOW.GetRepositoryAsync<Shift>().HasRecordsAsync(x => x.Name == item.Name && x.Status == true && x.ID != item.ID))
            {
                executionResult.AddMessageItem(new MessageItem(nameof(Shift.Name), "Name already exists"));
            }
        }
        public override async Task<Shift> GetById(Guid id)
        {
            return await UOW.GetRepositoryAsync<Shift>().SingleAsync(
                predicate: x => x.ID == id,
                orderBy: o => o.OrderByDescending(x => x.AddedAt));
        }

        public override async Task<IEnumerable<Shift>> GetList(string orderBy)
        {
            return await UOW.GetRepositoryAsync<Shift>().GetListAsync(orderBy, x => x.Status == true);
        }

        public override async Task<IPaginate<Shift>> GetPaginate(BaseSearch search)
        {
            return await UOW.GetRepositoryAsync<Shift>().GetPageListAsync(
                predicate: x => (string.IsNullOrEmpty(search.Name)
                     || x.Name.Contains(search.Name)
                     || x.Desciption.Contains(search.Name)),
                index: search.Page, size: search.Size, sortBy: search.SortBy ?? "Name", ascending: !search.IsDescend);
        }
